protected double reducedMass(double mSource, double mTarget) {
	if (mSource == Double.POSITIVE_INFINITY) return mTarget;
	if (mTarget == Double.POSITIVE_INFINITY) return mSource;
	return (mSource * mTarget) / (mSource + mTarget);
}

Point2D.Double calcUnitVec(Point lSource, Point lTarget, double distance) {
	return new Point2D.Double((lTarget.x - lSource.x) / distance, (lTarget.y - lSource.y) / distance);
}		

protected Point2D.Double impulse(Point2D.Double normalVec, Point vSource, Point vTarget, double reducedMass) {
	double vRelN = (vTarget.x - vSource.x) * normalVec.x + (vTarget.y - vSource.y) * normalVec.y;
	double impulseMag = 2.0 * reducedMass * vRelN;
	return new Point2D.Double(impulseMag * normalVec.x, impulseMag * normalVec.y);
}

private static final double NudgeFactor = 1.1;

Point calcNudgeVec(Point2D.Double normalVec, double minSeparation, double distance) {
	double nudgeMag = (minSeparation * NudgeFactor - distance) / 2.0;
	return new Point((int) Math.round(-nudgeMag * normalVec.x), (int) Math.round(-nudgeMag * normalVec.y));
}

protected void updateVelocity(IBall aBall, double mass, Point2D.Double impulseVec) {
	Point v = aBall.getVelocity();
	aBall.setVelocity(new Point((int) Math.round(v.x + impulseVec.x / mass), (int) Math.round(v.y + impulseVec.y / mass)));
}

