@Override
public IBallCmd interactWith(IBall source, IBall target, IDispatcher<IBallCmd> disp) {
	Point lSource = source.getLocation();
	Point lTarget = target.getLocation();
	double distance = lSource.distance(lTarget);
	double minSeparation = source.getRadius() + target.getRadius();

	if (distance < minSeparation) {
		double mSource = source.getRadius() * source.getRadius();
		double mTarget = target.getRadius() * target.getRadius();
		double rMass = reducedMass(mSource, mTarget);

		Point2D.Double normalVec = calcUnitVec(lSource, lTarget, distance);

		// Check if balls are approaching each other
		double vRelN = (target.getVelocity().x - source.getVelocity().x) * normalVec.x + 
		               (target.getVelocity().y - source.getVelocity().y) * normalVec.y;

		if (vRelN < 0) {
			Point2D.Double impulseVec = impulse(normalVec, source.getVelocity(), target.getVelocity(), rMass);
			updateVelocity(source, mSource, impulseVec);

			Point2D.Double impulseVecTarget = new Point2D.Double(-impulseVec.x, -impulseVec.y);
			updateVelocity(target, mTarget, impulseVecTarget);
		}

		Point nudge = calcNudgeVec(normalVec, minSeparation, distance);
		source.getLocation().translate(nudge.x, nudge.y);
		target.getLocation().translate(-nudge.x, -nudge.y);
	}

	return (context, d) -> {};
}

