package comp310.tests.hw05;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.awt.Color;
import java.awt.Point;
import java.util.ArrayList;
import java.util.List;

import hw05.model.Ball;
import hw05.model.IBall;
import hw05.model.IBallAlgo;
import hw05.model.IBallCmd;
import hw05.model.interactStrategies.ReproduceStrategy;
import provided.utils.displayModel.IDimension;
import provided.utils.dispatcher.IDispatcher;
import provided.utils.dispatcher.IObserver;

class ReproduceTest {

    private IDimension mockDim() {
        return new IDimension() {
            public int getWidth() { return 800; }
            public int getHeight() { return 600; }
        };
    }

    private IBallAlgo noOpAlgo() {
        return new IBallAlgo() {
            public void caseDefault(IBall host) {}
        };
    }

    @Test
    void testReproduceStrategyAddsBallToDispatcher() {
        List<IObserver<IBallCmd>> balls = new ArrayList<>();
        IDispatcher<IBallCmd> disp = new IDispatcher<IBallCmd>() {
            @Override public void addObserver(IObserver<IBallCmd> obs) { balls.add(obs); }
            @Override public void removeObserver(IObserver<IBallCmd> obs) {}
            @Override public void updateAll(IBallCmd cmd) {}
			@Override public void removeAllObservers() {}
        };

        Ball source = new Ball(new Point(100, 100), new Point(0, 0), Color.RED, 10, mockDim(), null, noOpAlgo());
        Ball target = new Ball(new Point(110, 110), new Point(0, 0), Color.BLUE, 20, mockDim(), null, noOpAlgo());

        ReproduceStrategy reproduce = new ReproduceStrategy();
        reproduce.interactWith(source, target, disp);

        assertEquals(1, balls.size(), "ReproduceStrategy should add exactly one ball to dispatcher per call");
        IBall offspring = (IBall) balls.get(0);

        assertEquals(15, offspring.getRadius(), "Offspring radius should be average of parents");
        assertEquals(new Color(127, 0, 127).getRGB(), offspring.getColor().getRGB(), "Offspring color should be average of parents (approx)");
    }
}
